window.DELTACORE_SEARCH_INDEX = [{"id":"adrs","title":"Engineering Decisions (ADRs)","section":"Engineering Decisions (ADRs)","url":"sections/adrs.html","text":"Engineering Decisions (ADRs) Architecture Decision Records — placeholder for documented decisions. adr decisions architecture ADR format Every major engineering decision records: Decision, Reason, Alternatives, Advantages, Disadvantages, Decision Date, Author. Decisions to document ADR-001 — Modular monolith vs microservices for pilot (recommended: monolith first) ADR-002 — PostgreSQL + TimescaleDB for telemetry time series ADR-003 — ASP.NET Core as primary stack vs Python/FastAPI for AI services ADR-004 — Separate public repo for Engineering Portal documentation","tags":["adr","decisions","architecture"],"status":"planned"},{"id":"adrs-adr-format","title":"ADR format","section":"Engineering Decisions (ADRs)","url":"sections/adrs.html#adr-format","text":"ADR format Every major engineering decision records: Decision, Reason, Alternatives, Advantages, Disadvantages, Decision Date, Author.","tags":["adr","decisions","architecture"],"status":"planned"},{"id":"adrs-pending-adrs","title":"Decisions to document","section":"Engineering Decisions (ADRs)","url":"sections/adrs.html#pending-adrs","text":"Decisions to document ADR-001 — Modular monolith vs microservices for pilot (recommended: monolith first) ADR-002 — PostgreSQL + TimescaleDB for telemetry time series ADR-003 — ASP.NET Core as primary stack vs Python/FastAPI for AI services ADR-004 — Separate public repo for Engineering Portal documentation","tags":["adr","decisions","architecture"],"status":"planned"},{"id":"ai-roadmap","title":"AI and MLOps","section":"AI and MLOps","url":"sections/ai-roadmap.html","text":"AI and MLOps AI roadmap, analytics maturity model and MLOps requirements. L1 L4 Colab scikit-learn ai mlops anomaly forecast maintenance Analytics maturity model L1 — Dashboards, KPIs, threshold rules (MVP target) L2 — Statistical anomaly detection and baseline forecasting (MVP target) L3 — Supervised models with labeled history (pilot extension) L4 — Adaptive optimization, fleet intelligence, edge inference (future) AI module roadmap Fuel Intelligence — forecast, anomaly, theft detection Predictive Maintenance — RUL, failure prediction (requires labeled data) Vision AI — undercarriage wear, component classification Training pipeline Obtain minimum 6 months historical fuel and telemetry data Engineer features aligned to canonical telemetry schema Train models (Colab initially, then automated jobs) Evaluate offline; register model weights with version metadata Deploy shadow-mode; monitor drift and retrain on approval MLOps requirements Model registry and versioning Feature and dataset versioning Experiment tracking and offline evaluation metrics Online monitoring for drift and performance degradation Confidence scores, explainability and minimum data thresholds","tags":["ai","mlops","anomaly","forecast","maintenance"],"status":"planned"},{"id":"ai-roadmap-maturity","title":"Analytics maturity model","section":"AI and MLOps","url":"sections/ai-roadmap.html#maturity","text":"Analytics maturity model L1 — Dashboards, KPIs, threshold rules (MVP target) L2 — Statistical anomaly detection and baseline forecasting (MVP target) L3 — Supervised models with labeled history (pilot extension) L4 — Adaptive optimization, fleet intelligence, edge inference (future)","tags":["ai","mlops","anomaly","forecast","maintenance"],"status":"planned"},{"id":"ai-roadmap-modules","title":"AI module roadmap","section":"AI and MLOps","url":"sections/ai-roadmap.html#modules","text":"AI module roadmap Fuel Intelligence — forecast, anomaly, theft detection Predictive Maintenance — RUL, failure prediction (requires labeled data) Vision AI — undercarriage wear, component classification","tags":["ai","mlops","anomaly","forecast","maintenance"],"status":"planned"},{"id":"ai-roadmap-training-pipeline","title":"Training pipeline","section":"AI and MLOps","url":"sections/ai-roadmap.html#training-pipeline","text":"Training pipeline Obtain minimum 6 months historical fuel and telemetry data Engineer features aligned to canonical telemetry schema Train models (Colab initially, then automated jobs) Evaluate offline; register model weights with version metadata Deploy shadow-mode; monitor drift and retrain on approval","tags":["ai","mlops","anomaly","forecast","maintenance"],"status":"planned"},{"id":"ai-roadmap-mlops","title":"MLOps requirements","section":"AI and MLOps","url":"sections/ai-roadmap.html#mlops","text":"MLOps requirements Model registry and versioning Feature and dataset versioning Experiment tracking and offline evaluation metrics Online monitoring for drift and performance degradation Confidence scores, explainability and minimum data thresholds","tags":["ai","mlops","anomaly","forecast","maintenance"],"status":"planned"},{"id":"alerts","title":"Alert Engine","section":"Alert Engine","url":"sections/alerts.html","text":"Alert Engine First-class alerting with rules and model-driven detections. acknowledged critical confidence alerts severity anomaly fuel theft Overview Alerting is a first-class product capability supporting deterministic rules and model-driven detections with human-readable explanations. Alert lifecycle Severity: info, warning, critical Status: open, acknowledged, resolved, dismissed Fields: alert_type, confidence, explanation, recommended_action Deduplication and suppression to reduce noise Feedback loop to monitor false positives Example alert types fuel_anomaly — rapid drop in fuel level theft_suspect — fuel loss without corresponding usage excessive_idle — abnormal idle fuel consumption","tags":["alerts","severity","anomaly","fuel theft"],"status":"planned"},{"id":"alerts-overview","title":"Overview","section":"Alert Engine","url":"sections/alerts.html#overview","text":"Overview Alerting is a first-class product capability supporting deterministic rules and model-driven detections with human-readable explanations.","tags":["alerts","severity","anomaly","fuel theft"],"status":"planned"},{"id":"alerts-lifecycle","title":"Alert lifecycle","section":"Alert Engine","url":"sections/alerts.html#lifecycle","text":"Alert lifecycle Severity: info, warning, critical Status: open, acknowledged, resolved, dismissed Fields: alert_type, confidence, explanation, recommended_action Deduplication and suppression to reduce noise Feedback loop to monitor false positives","tags":["alerts","severity","anomaly","fuel theft"],"status":"planned"},{"id":"alerts-examples","title":"Example alert types","section":"Alert Engine","url":"sections/alerts.html#examples","text":"Example alert types fuel_anomaly — rapid drop in fuel level theft_suspect — fuel loss without corresponding usage excessive_idle — abnormal idle fuel consumption","tags":["alerts","severity","anomaly","fuel theft"],"status":"planned"},{"id":"api","title":"API Documentation","section":"API Documentation","url":"sections/api.html","text":"API Documentation REST API standards and Swagger documentation. api rest openapi swagger jwt API standards REST with OpenAPI specification JWT authentication Versioned endpoints under /api/v1 Consistent error model Pagination and filtering on all list endpoints API categories External customer API Provider ingestion API Internal service-to-service APIs Administration API Webhooks and event interfaces (future) Interactive documentation When running locally, Swagger UI is available at https://localhost:5001/swagger. Entity CRUD endpoints are generated per domain model.","tags":["api","rest","openapi","swagger","jwt"],"status":"live"},{"id":"api-standards","title":"API standards","section":"API Documentation","url":"sections/api.html#standards","text":"API standards REST with OpenAPI specification JWT authentication Versioned endpoints under /api/v1 Consistent error model Pagination and filtering on all list endpoints","tags":["api","rest","openapi","swagger","jwt"],"status":"live"},{"id":"api-categories","title":"API categories","section":"API Documentation","url":"sections/api.html#categories","text":"API categories External customer API Provider ingestion API Internal service-to-service APIs Administration API Webhooks and event interfaces (future)","tags":["api","rest","openapi","swagger","jwt"],"status":"live"},{"id":"api-swagger","title":"Interactive documentation","section":"API Documentation","url":"sections/api.html#swagger","text":"Interactive documentation When running locally, Swagger UI is available at https://localhost:5001/swagger. Entity CRUD endpoints are generated per domain model.","tags":["api","rest","openapi","swagger","jwt"],"status":"live"},{"id":"architecture","title":"Architecture","section":"Architecture","url":"sections/architecture.html","text":"Architecture Tiered architecture from POC modular monolith to target microservices. TimescaleDB Redis API Gateway architecture monolith microservices fastapi Tiered deployment strategy Logical service boundaries are defined upfront. Physical deployment starts as a modular monolith for pilot speed, decomposing at M8 when scale or isolation requires it. POC — Single FastAPI or ASP.NET app + demo UI (rapid iteration) Pilot MVP — Modular monolith + managed PostgreSQL (current .NET path) Production — API Gateway + microservices + event bus + full observability Core modules Identity and Security Multi-tenant Company Management Mine and Site Management Fleet and Equipment Telemetry Ingestion Fuel Intelligence Predictive Maintenance Alerting Reporting AI Services Administration Data flow Equipment and sensors → telematics providers → provider adapters → canonical telemetry → analytics and AI engine → alerts and dashboards. Failed records are quarantined for replay; data quality is scored.","tags":["architecture","monolith","microservices","fastapi"],"status":"in_progress"},{"id":"architecture-tiered-approach","title":"Tiered deployment strategy","section":"Architecture","url":"sections/architecture.html#tiered-approach","text":"Tiered deployment strategy Logical service boundaries are defined upfront. Physical deployment starts as a modular monolith for pilot speed, decomposing at M8 when scale or isolation requires it. POC — Single FastAPI or ASP.NET app + demo UI (rapid iteration) Pilot MVP — Modular monolith + managed PostgreSQL (current .NET path) Production — API Gateway + microservices + event bus + full observability","tags":["architecture","monolith","microservices","fastapi"],"status":"in_progress"},{"id":"architecture-core-modules","title":"Core modules","section":"Architecture","url":"sections/architecture.html#core-modules","text":"Core modules Identity and Security Multi-tenant Company Management Mine and Site Management Fleet and Equipment Telemetry Ingestion Fuel Intelligence Predictive Maintenance Alerting Reporting AI Services Administration","tags":["architecture","monolith","microservices","fastapi"],"status":"in_progress"},{"id":"architecture-data-flow","title":"Data flow","section":"Architecture","url":"sections/architecture.html#data-flow","text":"Data flow Equipment and sensors → telematics providers → provider adapters → canonical telemetry → analytics and AI engine → alerts and dashboards. Failed records are quarantined for replay; data quality is scored.","tags":["architecture","monolith","microservices","fastapi"],"status":"in_progress"},{"id":"entities","title":"Database and Entities","section":"Database and Entities","url":"sections/entities.html","text":"Database and Entities Core domain entities in the DeltaCore data model. FuelEvent Alert Role Integration entities database postgresql company equipment Tenant hierarchy Company is the tenant root. Mine → Site → Equipment forms the operational hierarchy. All tenant-scoped entities carry Company_Id for isolation. Core entities (Phase 1) Company, Mine, Site, Equipment — asset registry Sensor — equipment-attached sensors Integration — provider connection configuration FuelEvent — fuel consumption, refuel and anomaly events Alert — operational alerts with lifecycle and severity User, Role — RBAC foundation Operator — Phase 2 operator scoring MaintenanceRecord, Prediction — Phase 2 maintenance AI TelemetryReading — high-volume time series (Phase 2 / Timescale) Database scripts SQL scripts live in scripts/postgresql/: 001-create-tables.sql and 002-seed-data.sql. Development may use EF EnsureCreated when enabled in appsettings.","tags":["entities","database","postgresql","company","equipment"],"status":"live"},{"id":"entities-hierarchy","title":"Tenant hierarchy","section":"Database and Entities","url":"sections/entities.html#hierarchy","text":"Tenant hierarchy Company is the tenant root. Mine → Site → Equipment forms the operational hierarchy. All tenant-scoped entities carry Company_Id for isolation.","tags":["entities","database","postgresql","company","equipment"],"status":"live"},{"id":"entities-core-entities","title":"Core entities (Phase 1)","section":"Database and Entities","url":"sections/entities.html#core-entities","text":"Core entities (Phase 1) Company, Mine, Site, Equipment — asset registry Sensor — equipment-attached sensors Integration — provider connection configuration FuelEvent — fuel consumption, refuel and anomaly events Alert — operational alerts with lifecycle and severity User, Role — RBAC foundation Operator — Phase 2 operator scoring MaintenanceRecord, Prediction — Phase 2 maintenance AI TelemetryReading — high-volume time series (Phase 2 / Timescale)","tags":["entities","database","postgresql","company","equipment"],"status":"live"},{"id":"entities-scripts","title":"Database scripts","section":"Database and Entities","url":"sections/entities.html#scripts","text":"Database scripts SQL scripts live in scripts/postgresql/: 001-create-tables.sql and 002-seed-data.sql. Development may use EF EnsureCreated when enabled in appsettings.","tags":["entities","database","postgresql","company","equipment"],"status":"live"},{"id":"faq","title":"Frequently Asked Questions","section":"Frequently Asked Questions","url":"sections/faq.html","text":"Frequently Asked Questions Open questions and common answers. faq questions FAQ Does DeltaCore replace PetroMan or AVA? — No. DeltaCore augments existing providers as an intelligence layer. Is the product source code public? — No. DeltaCore source is private. This portal is a curated public documentation site. What is built today? — AppGen-scaffolded API, MVC admin, PostgreSQL schema and core entity CRUD. When will live PetroMan data be integrated? — Target M2–M7 pilot milestones after provider API access. Why a separate portal repo? — To share vision and architecture without exposing proprietary source code. How do I update portal content? — Edit portal/data/*.json in the private repo, run build-portal.ps1, push; CI deploys to public portal repo. Open questions (to resolve) First pilot scope and site selection Commercial licensing and multi-tenant pricing PetroMan / AVA API specifications and access process SLA expectations and support model for pilot","tags":["faq","questions"],"status":"live"},{"id":"faq-faq-items","title":"FAQ","section":"Frequently Asked Questions","url":"sections/faq.html#faq-items","text":"FAQ Does DeltaCore replace PetroMan or AVA? — No. DeltaCore augments existing providers as an intelligence layer. Is the product source code public? — No. DeltaCore source is private. This portal is a curated public documentation site. What is built today? — AppGen-scaffolded API, MVC admin, PostgreSQL schema and core entity CRUD. When will live PetroMan data be integrated? — Target M2–M7 pilot milestones after provider API access. Why a separate portal repo? — To share vision and architecture without exposing proprietary source code. How do I update portal content? — Edit portal/data/*.json in the private repo, run build-portal.ps1, push; CI deploys to public portal repo.","tags":["faq","questions"],"status":"live"},{"id":"faq-open-questions","title":"Open questions (to resolve)","section":"Frequently Asked Questions","url":"sections/faq.html#open-questions","text":"Open questions (to resolve) First pilot scope and site selection Commercial licensing and multi-tenant pricing PetroMan / AVA API specifications and access process SLA expectations and support model for pilot","tags":["faq","questions"],"status":"live"},{"id":"fuel-intelligence","title":"Fuel Intelligence","section":"Fuel Intelligence","url":"sections/fuel-intelligence.html","text":"Fuel Intelligence Phase 1 commercial module — fuel analytics and loss prevention. fuel theft anomaly forecast phase 1 Capabilities Forecast fuel consumption (statistical baselines initially) Detect anomalies and abnormal consumption patterns Support fuel theft detection with explainable alerts Refueling optimization insights (Phase 1.5) Equipment-level and fleet-level fuel dashboards Current status FuelEvent entity and CRUD API exist. Analytics engine, forecasting models and production dashboards are planned for M4–M6.","tags":["fuel","theft","anomaly","forecast","phase 1"],"status":"planned"},{"id":"fuel-intelligence-capabilities","title":"Capabilities","section":"Fuel Intelligence","url":"sections/fuel-intelligence.html#capabilities","text":"Capabilities Forecast fuel consumption (statistical baselines initially) Detect anomalies and abnormal consumption patterns Support fuel theft detection with explainable alerts Refueling optimization insights (Phase 1.5) Equipment-level and fleet-level fuel dashboards","tags":["fuel","theft","anomaly","forecast","phase 1"],"status":"planned"},{"id":"fuel-intelligence-mvp-status","title":"Current status","section":"Fuel Intelligence","url":"sections/fuel-intelligence.html#mvp-status","text":"Current status FuelEvent entity and CRUD API exist. Analytics engine, forecasting models and production dashboards are planned for M4–M6.","tags":["fuel","theft","anomaly","forecast","phase 1"],"status":"planned"},{"id":"future-expansion","title":"Future Expansion","section":"Future Expansion","url":"sections/future-expansion.html","text":"Future Expansion Phase 2+ platform expansion items. future erp cmms edge mobile Future capabilities ERP and CMMS integrations Edge gateway and native mobile applications Digital twins and customer-specific AI models Cross-mine fleet benchmarking Operator behavior scoring and GPS geofencing Dedicated rugged hardware platform with edge inference In-browser portal editing and advanced hosting (Phase 2 portal) Future hardware platform Rugged industrial edge device: CAN Bus, J1939, GPS, LTE/5G, secure communications, optional edge inference. Device hosts models and gathers data — it is not the AI itself.","tags":["future","erp","cmms","edge","mobile"],"status":"planned"},{"id":"future-expansion-expansion-items","title":"Future capabilities","section":"Future Expansion","url":"sections/future-expansion.html#expansion-items","text":"Future capabilities ERP and CMMS integrations Edge gateway and native mobile applications Digital twins and customer-specific AI models Cross-mine fleet benchmarking Operator behavior scoring and GPS geofencing Dedicated rugged hardware platform with edge inference In-browser portal editing and advanced hosting (Phase 2 portal)","tags":["future","erp","cmms","edge","mobile"],"status":"planned"},{"id":"future-expansion-hardware","title":"Future hardware platform","section":"Future Expansion","url":"sections/future-expansion.html#hardware","text":"Future hardware platform Rugged industrial edge device: CAN Bus, J1939, GPS, LTE/5G, secure communications, optional edge inference. Device hosts models and gathers data — it is not the AI itself.","tags":["future","erp","cmms","edge","mobile"],"status":"planned"},{"id":"getting-started","title":"Getting Started","section":"Getting Started","url":"sections/getting-started.html","text":"Getting Started Current repository state, how to run DeltaCore, and how this portal relates to the product. AppGen Live Server PostgreSQL mission control repository run swagger Welcome DeltaCore is an industrial intelligence platform for mining, construction, fleet, plant hire and logistics. This portal documents vision, architecture, standards and roadmap. The product source code lives in a private repository; this public site contains documentation only. Current state The solution is an AppGen-scaffolded ASP.NET Core foundation with PostgreSQL, REST API, MVC admin UI, and core domain entities (Company, Mine, Site, Equipment, Fuel, Alerts, Users). M1 foundation: database schema, authentication data model, CRUD API and MVC — in progress / live Telemetry ingestion, fuel analytics engine, and production AI — planned Existing POC: Streamlit dashboard on GitHub (DeltaCoreAI org) — separate from this .NET foundation Run the product locally From the private DeltaCore repository: Update connection strings in src/DeltaCore.API/appsettings.json Run scripts/postgresql/001-create-tables.sql and optionally 002-seed-data.sql dotnet build DeltaCore.sln API Swagger: https://localhost:5001/swagger MVC UI: https://localhost:5101 Portal vs MVC vs API DeltaCore.API — platform backend and REST endpoints DeltaCore.MVC — operational admin (equipment, alerts, fuel events) Engineering Portal (this site) — vision, architecture, standards for sharing","tags":["mission control","repository","run","swagger"],"status":"live"},{"id":"getting-started-welcome","title":"Welcome","section":"Getting Started","url":"sections/getting-started.html#welcome","text":"Welcome DeltaCore is an industrial intelligence platform for mining, construction, fleet, plant hire and logistics. This portal documents vision, architecture, standards and roadmap. The product source code lives in a private repository; this public site contains documentation only.","tags":["mission control","repository","run","swagger"],"status":"live"},{"id":"getting-started-current-state","title":"Current state","section":"Getting Started","url":"sections/getting-started.html#current-state","text":"Current state The solution is an AppGen-scaffolded ASP.NET Core foundation with PostgreSQL, REST API, MVC admin UI, and core domain entities (Company, Mine, Site, Equipment, Fuel, Alerts, Users). M1 foundation: database schema, authentication data model, CRUD API and MVC — in progress / live Telemetry ingestion, fuel analytics engine, and production AI — planned Existing POC: Streamlit dashboard on GitHub (DeltaCoreAI org) — separate from this .NET foundation","tags":["mission control","repository","run","swagger"],"status":"live"},{"id":"getting-started-run-product","title":"Run the product locally","section":"Getting Started","url":"sections/getting-started.html#run-product","text":"Run the product locally From the private DeltaCore repository: Update connection strings in src/DeltaCore.API/appsettings.json Run scripts/postgresql/001-create-tables.sql and optionally 002-seed-data.sql dotnet build DeltaCore.sln API Swagger: https://localhost:5001/swagger MVC UI: https://localhost:5101","tags":["mission control","repository","run","swagger"],"status":"live"},{"id":"getting-started-portal-vs-mvc","title":"Portal vs MVC vs API","section":"Getting Started","url":"sections/getting-started.html#portal-vs-mvc","text":"Portal vs MVC vs API DeltaCore.API — platform backend and REST endpoints DeltaCore.MVC — operational admin (equipment, alerts, fuel events) Engineering Portal (this site) — vision, architecture, standards for sharing","tags":["mission control","repository","run","swagger"],"status":"live"},{"id":"infrastructure","title":"Infrastructure and Deployment","section":"Infrastructure and Deployment","url":"sections/infrastructure.html","text":"Infrastructure and Deployment Environments, non-functional requirements and deployment approach. RPO RTO 99.5 deployment nfr docker azure ci cd Environments Local development Shared development Staging / UAT Pilot production Full production Technology stack Backend: ASP.NET Core (FastAPI optional alternative) Database: PostgreSQL (+ TimescaleDB for telemetry later) Cache: Redis (later phases) Containers: Docker CI/CD: GitHub Actions Monitoring: Grafana + Prometheus Logging: OpenTelemetry Non-functional requirements (pilot targets) API availability: 99.5% Telemetry ingestion delay: under 5 minutes Dashboard load time: under 3 seconds Alert generation delay: under 2 minutes after qualifying event Telemetry retention: 24 months configurable Backup RPO: 24 hours | RTO: 8 hours Engineering Portal hosting Portal static files are built from portal/ in the private DeltaCore repo and published to a separate public DeltaCore-Portal repository via GitHub Actions. No product source code is deployed to the public site.","tags":["deployment","nfr","docker","azure","ci cd"],"status":"planned"},{"id":"infrastructure-environments","title":"Environments","section":"Infrastructure and Deployment","url":"sections/infrastructure.html#environments","text":"Environments Local development Shared development Staging / UAT Pilot production Full production","tags":["deployment","nfr","docker","azure","ci cd"],"status":"planned"},{"id":"infrastructure-stack","title":"Technology stack","section":"Infrastructure and Deployment","url":"sections/infrastructure.html#stack","text":"Technology stack Backend: ASP.NET Core (FastAPI optional alternative) Database: PostgreSQL (+ TimescaleDB for telemetry later) Cache: Redis (later phases) Containers: Docker CI/CD: GitHub Actions Monitoring: Grafana + Prometheus Logging: OpenTelemetry","tags":["deployment","nfr","docker","azure","ci cd"],"status":"planned"},{"id":"infrastructure-nfrs","title":"Non-functional requirements (pilot targets)","section":"Infrastructure and Deployment","url":"sections/infrastructure.html#nfrs","text":"Non-functional requirements (pilot targets) API availability: 99.5% Telemetry ingestion delay: under 5 minutes Dashboard load time: under 3 seconds Alert generation delay: under 2 minutes after qualifying event Telemetry retention: 24 months configurable Backup RPO: 24 hours | RTO: 8 hours","tags":["deployment","nfr","docker","azure","ci cd"],"status":"planned"},{"id":"infrastructure-portal-hosting","title":"Engineering Portal hosting","section":"Infrastructure and Deployment","url":"sections/infrastructure.html#portal-hosting","text":"Engineering Portal hosting Portal static files are built from portal/ in the private DeltaCore repo and published to a separate public DeltaCore-Portal repository via GitHub Actions. No product source code is deployed to the public site.","tags":["deployment","nfr","docker","azure","ci cd"],"status":"planned"},{"id":"integrations","title":"Integrations and Partnership Strategy","section":"Integrations and Partnership Strategy","url":"sections/integrations.html","text":"Integrations and Partnership Strategy Staged provider onboarding and partnership approach. shadow mode white label revenue share petroman ava dingo integration partnership Partnership strategy Approach incumbent telematics providers as allies. DeltaCore acts as an AI enhancement layer through APIs, white-label products and revenue-sharing arrangements. PetroMan integration phases Phase 1 — Read-only API integration (no operational change) Phase 2 — Shadow-mode analytics (insights in DeltaCore only) Phase 3 — Demonstrate measurable ROI Phase 4 — Operational deployment with alerts and optional edge agents Data source catalog PetroMan — fuel level, consumption, refuel events (Phase 1, primary) AVA — GPS, engine hours, telemetry, faults (Phase 1, primary) Dingo — fleet telematics (Phase 2) CAN/J1939 — engine and fuel rate via edge adapter (Phase 2) Simulated data — CSV/generator for POC and demos (now) Integration framework requirements Provider adapters translate APIs into canonical schema Idempotent ingestion with deduplication keys Authentication rotation, rate limits, retries and audit trails Quarantine failed records for replay Equipment ID mapping between provider and DeltaCore records","tags":["petroman","ava","dingo","integration","partnership"],"status":"planned"},{"id":"integrations-strategy","title":"Partnership strategy","section":"Integrations and Partnership Strategy","url":"sections/integrations.html#strategy","text":"Partnership strategy Approach incumbent telematics providers as allies. DeltaCore acts as an AI enhancement layer through APIs, white-label products and revenue-sharing arrangements.","tags":["petroman","ava","dingo","integration","partnership"],"status":"planned"},{"id":"integrations-petroman-phases","title":"PetroMan integration phases","section":"Integrations and Partnership Strategy","url":"sections/integrations.html#petroman-phases","text":"PetroMan integration phases Phase 1 — Read-only API integration (no operational change) Phase 2 — Shadow-mode analytics (insights in DeltaCore only) Phase 3 — Demonstrate measurable ROI Phase 4 — Operational deployment with alerts and optional edge agents","tags":["petroman","ava","dingo","integration","partnership"],"status":"planned"},{"id":"integrations-provider-catalog","title":"Data source catalog","section":"Integrations and Partnership Strategy","url":"sections/integrations.html#provider-catalog","text":"Data source catalog PetroMan — fuel level, consumption, refuel events (Phase 1, primary) AVA — GPS, engine hours, telemetry, faults (Phase 1, primary) Dingo — fleet telematics (Phase 2) CAN/J1939 — engine and fuel rate via edge adapter (Phase 2) Simulated data — CSV/generator for POC and demos (now)","tags":["petroman","ava","dingo","integration","partnership"],"status":"planned"},{"id":"integrations-framework","title":"Integration framework requirements","section":"Integrations and Partnership Strategy","url":"sections/integrations.html#framework","text":"Integration framework requirements Provider adapters translate APIs into canonical schema Idempotent ingestion with deduplication keys Authentication rotation, rate limits, retries and audit trails Quarantine failed records for replay Equipment ID mapping between provider and DeltaCore records","tags":["petroman","ava","dingo","integration","partnership"],"status":"planned"},{"id":"mvp-scope","title":"MVP Scope","section":"MVP Scope","url":"sections/mvp-scope.html","text":"MVP Scope What is in and out of scope for the first pilot release. mvp pilot scope fuel In scope for MVP / pilot Company, site, fleet and equipment management Telemetry ingestion from simulated or live provider feeds Fuel analytics, anomaly detection, health scoring and alerting Investor-ready dashboard and reporting views Role-based authentication and REST APIs Shadow-mode analytics alongside existing provider platforms Initial statistical anomaly detection (analytics maturity L1–L2) Out of scope for MVP Custom AI chip development Full autonomous edge hardware platform Production-grade multi-region scale from day one Advanced supervised ML requiring unavailable labeled data GPS geofencing and operator scoring (Phase 2) Engineering principles Reliable ingestion and clean data before sophisticated models Integrate into existing systems first Explainable analytics before opaque models Design for future scale; optimize MVP for pilot ROI Modular monolith for pilot; decompose when scale demands Pilot success criteria Ingest data from at least one live provider Onboard at least one real pilot site with stable daily ingestion Detect and surface actionable fuel anomalies Identify at least one credible cost-saving or loss-prevention opportunity Establish baseline analytics accuracy metrics","tags":["mvp","pilot","scope","fuel"],"status":"in_progress"},{"id":"mvp-scope-in-scope","title":"In scope for MVP / pilot","section":"MVP Scope","url":"sections/mvp-scope.html#in-scope","text":"In scope for MVP / pilot Company, site, fleet and equipment management Telemetry ingestion from simulated or live provider feeds Fuel analytics, anomaly detection, health scoring and alerting Investor-ready dashboard and reporting views Role-based authentication and REST APIs Shadow-mode analytics alongside existing provider platforms Initial statistical anomaly detection (analytics maturity L1–L2)","tags":["mvp","pilot","scope","fuel"],"status":"in_progress"},{"id":"mvp-scope-out-of-scope","title":"Out of scope for MVP","section":"MVP Scope","url":"sections/mvp-scope.html#out-of-scope","text":"Out of scope for MVP Custom AI chip development Full autonomous edge hardware platform Production-grade multi-region scale from day one Advanced supervised ML requiring unavailable labeled data GPS geofencing and operator scoring (Phase 2)","tags":["mvp","pilot","scope","fuel"],"status":"in_progress"},{"id":"mvp-scope-engineering-principles","title":"Engineering principles","section":"MVP Scope","url":"sections/mvp-scope.html#engineering-principles","text":"Engineering principles Reliable ingestion and clean data before sophisticated models Integrate into existing systems first Explainable analytics before opaque models Design for future scale; optimize MVP for pilot ROI Modular monolith for pilot; decompose when scale demands","tags":["mvp","pilot","scope","fuel"],"status":"in_progress"},{"id":"mvp-scope-pilot-success","title":"Pilot success criteria","section":"MVP Scope","url":"sections/mvp-scope.html#pilot-success","text":"Pilot success criteria Ingest data from at least one live provider Onboard at least one real pilot site with stable daily ingestion Detect and surface actionable fuel anomalies Identify at least one credible cost-saving or loss-prevention opportunity Establish baseline analytics accuracy metrics","tags":["mvp","pilot","scope","fuel"],"status":"in_progress"},{"id":"research","title":"Research","section":"Research","url":"sections/research.html","text":"Research Technical research topics for future phases. Azure CAN Bus research petroman mqtt timescaledb j1939 Research topics PetroMan API access process and data formats AVA telematics integration specifications MQTT and Kafka for event-driven architecture CAN Bus and J1939 edge gateway design TimescaleDB hypertables for telemetry at scale Azure deployment options for pilot environments","tags":["research","petroman","mqtt","timescaledb","j1939"],"status":"planned"},{"id":"research-topics","title":"Research topics","section":"Research","url":"sections/research.html#topics","text":"Research topics PetroMan API access process and data formats AVA telematics integration specifications MQTT and Kafka for event-driven architecture CAN Bus and J1939 edge gateway design TimescaleDB hypertables for telemetry at scale Azure deployment options for pilot environments","tags":["research","petroman","mqtt","timescaledb","j1939"],"status":"planned"},{"id":"roadmap","title":"Product Roadmap","section":"Product Roadmap","url":"sections/roadmap.html","text":"Product Roadmap Phase 1 Fuel Intelligence through Phase 3 Vision AI and future hardware. M0 M8 undercarriage roadmap phase maintenance vision ai Product phases Phase 1 — Fuel Intelligence (commercial first module) Phase 2 — Predictive Maintenance AI Phase 3 — Undercarriage Vision AI Future — Edge hardware and fleet-wide adaptive intelligence Engineering milestones (M0–M8) M0 — Architecture and specifications M1 — Database and authentication (current foundation) M2 — Telemetry ingestion and canonical normalization M3 — Fleet dashboard and health score widget M4 — Fuel analytics module M5 — Alert engine M6 — AI proof of concept and investor demo M7 — Pilot deployment with live provider data M8 — Production hardening and service decomposition Provider integration phases Phase 1 — Read-only API integration Phase 2 — Shadow-mode analytics Phase 3 — Demonstrate measurable ROI Phase 4 — Operational deployment","tags":["roadmap","phase","maintenance","vision ai"],"status":"live"},{"id":"roadmap-product-phases","title":"Product phases","section":"Product Roadmap","url":"sections/roadmap.html#product-phases","text":"Product phases Phase 1 — Fuel Intelligence (commercial first module) Phase 2 — Predictive Maintenance AI Phase 3 — Undercarriage Vision AI Future — Edge hardware and fleet-wide adaptive intelligence","tags":["roadmap","phase","maintenance","vision ai"],"status":"live"},{"id":"roadmap-milestones","title":"Engineering milestones (M0–M8)","section":"Product Roadmap","url":"sections/roadmap.html#milestones","text":"Engineering milestones (M0–M8) M0 — Architecture and specifications M1 — Database and authentication (current foundation) M2 — Telemetry ingestion and canonical normalization M3 — Fleet dashboard and health score widget M4 — Fuel analytics module M5 — Alert engine M6 — AI proof of concept and investor demo M7 — Pilot deployment with live provider data M8 — Production hardening and service decomposition","tags":["roadmap","phase","maintenance","vision ai"],"status":"live"},{"id":"roadmap-integration-phases","title":"Provider integration phases","section":"Product Roadmap","url":"sections/roadmap.html#integration-phases","text":"Provider integration phases Phase 1 — Read-only API integration Phase 2 — Shadow-mode analytics Phase 3 — Demonstrate measurable ROI Phase 4 — Operational deployment","tags":["roadmap","phase","maintenance","vision ai"],"status":"live"},{"id":"security","title":"Security and Data Governance","section":"Security and Data Governance","url":"sections/security.html","text":"Security and Data Governance RBAC, encryption, audit logging and data ownership. security rbac mfa governance audit Security controls RBAC with MFA support Encrypted communications (TLS) Secrets management — never commit credentials Audit logging and least-privilege access Regular backups and disaster recovery planning Future hardware: device identity, secure boot, firmware signing Multi-tenancy Default: shared database with strict tenant isolation via tenant_id. Cross-tenant analytics disabled unless explicitly contracted and anonymized. Data governance Customers own raw operational data unless contracts define otherwise Derived features and model outputs require clear contractual terms Provider-originated data usage complies with partner agreements All ingestion, transformation and access actions are auditable","tags":["security","rbac","mfa","governance","audit"],"status":"in_progress"},{"id":"security-security-controls","title":"Security controls","section":"Security and Data Governance","url":"sections/security.html#security-controls","text":"Security controls RBAC with MFA support Encrypted communications (TLS) Secrets management — never commit credentials Audit logging and least-privilege access Regular backups and disaster recovery planning Future hardware: device identity, secure boot, firmware signing","tags":["security","rbac","mfa","governance","audit"],"status":"in_progress"},{"id":"security-multi-tenancy","title":"Multi-tenancy","section":"Security and Data Governance","url":"sections/security.html#multi-tenancy","text":"Multi-tenancy Default: shared database with strict tenant isolation via tenant_id. Cross-tenant analytics disabled unless explicitly contracted and anonymized.","tags":["security","rbac","mfa","governance","audit"],"status":"in_progress"},{"id":"security-governance","title":"Data governance","section":"Security and Data Governance","url":"sections/security.html#governance","text":"Data governance Customers own raw operational data unless contracts define otherwise Derived features and model outputs require clear contractual terms Provider-originated data usage complies with partner agreements All ingestion, transformation and access actions are auditable","tags":["security","rbac","mfa","governance","audit"],"status":"in_progress"},{"id":"solution-structure","title":"Solution Structure","section":"Solution Structure","url":"sections/solution-structure.html","text":"Solution Structure DeltaCore.sln layered projects and responsibilities. solution AppGen layers projects Solution projects DeltaCore.API — REST API, Swagger, OpenAPI, API versioning DeltaCore.Application — application services and use cases DeltaCore.Domain — domain entities DeltaCore.Persistence — EF Core, DbContext, repositories DeltaCore.Shared — DTOs and shared contracts DeltaCore.MVC — optional MVC admin UI (calls API via HttpClient) DeltaCore.Tests — automated tests Engineering Portal (separate) The Engineering Portal is a static documentation site. It is not part of DeltaCore.sln. Source is maintained in portal/ within the private repo and published to a separate public documentation repository via CI.","tags":["solution","AppGen","layers","projects"],"status":"live"},{"id":"solution-structure-projects","title":"Solution projects","section":"Solution Structure","url":"sections/solution-structure.html#projects","text":"Solution projects DeltaCore.API — REST API, Swagger, OpenAPI, API versioning DeltaCore.Application — application services and use cases DeltaCore.Domain — domain entities DeltaCore.Persistence — EF Core, DbContext, repositories DeltaCore.Shared — DTOs and shared contracts DeltaCore.MVC — optional MVC admin UI (calls API via HttpClient) DeltaCore.Tests — automated tests","tags":["solution","AppGen","layers","projects"],"status":"live"},{"id":"solution-structure-portal-separate","title":"Engineering Portal (separate)","section":"Solution Structure","url":"sections/solution-structure.html#portal-separate","text":"Engineering Portal (separate) The Engineering Portal is a static documentation site. It is not part of DeltaCore.sln. Source is maintained in portal/ within the private repo and published to a separate public documentation repository via CI.","tags":["solution","AppGen","layers","projects"],"status":"live"},{"id":"standards","title":"Development Standards","section":"Development Standards","url":"sections/standards.html","text":"Development Standards Engineering standards and definition of done. clean architecture solid testing adr Architecture standards Clean Architecture with clear layer boundaries SOLID principles Repository and Unit of Work patterns where appropriate Dependency injection Structured logging Architecture Decision Records (ADRs) for major decisions Definition of done No feature is complete until all three are updated: Code — merged with review Tests — unit and integration where appropriate Documentation — portal or ADR updated for architectural or product changes Git workflow Feature branches and pull requests Migration-controlled database changes Secrets managed outside source control","tags":["clean architecture","solid","testing","adr"],"status":"live"},{"id":"standards-architecture-standards","title":"Architecture standards","section":"Development Standards","url":"sections/standards.html#architecture-standards","text":"Architecture standards Clean Architecture with clear layer boundaries SOLID principles Repository and Unit of Work patterns where appropriate Dependency injection Structured logging Architecture Decision Records (ADRs) for major decisions","tags":["clean architecture","solid","testing","adr"],"status":"live"},{"id":"standards-definition-of-done","title":"Definition of done","section":"Development Standards","url":"sections/standards.html#definition-of-done","text":"Definition of done No feature is complete until all three are updated: Code — merged with review Tests — unit and integration where appropriate Documentation — portal or ADR updated for architectural or product changes","tags":["clean architecture","solid","testing","adr"],"status":"live"},{"id":"standards-git-workflow","title":"Git workflow","section":"Development Standards","url":"sections/standards.html#git-workflow","text":"Git workflow Feature branches and pull requests Migration-controlled database changes Secrets managed outside source control","tags":["clean architecture","solid","testing","adr"],"status":"live"},{"id":"telemetry","title":"Canonical Telemetry","section":"Canonical Telemetry","url":"sections/telemetry.html","text":"Canonical Telemetry Normalized telemetry schema for multi-provider ingestion. CAN metric_type tenant_id telemetry ingestion normalization j1939 Why canonical telemetry DeltaCore sits above multiple providers. All inbound telemetry must be normalized into a canonical schema before analytics or alerting. Key fields timestamp_utc, tenant_id, site_id, equipment_id source_provider, source_asset_id metric_type, metric_unit, numeric_value status_or_quality_flag, data_quality_score latitude, longitude, engine_hours, odometer fuel_level, fuel_rate, ignition_state Telemetry rules Define accepted units and standard conversion rules Support event-based and time-series telemetry Track missing data, delayed records and duplicates Maintain raw-provider references for auditability and replay Idempotent ingestion using provider event IDs or hashes","tags":["telemetry","ingestion","normalization","j1939"],"status":"planned"},{"id":"telemetry-why-canonical","title":"Why canonical telemetry","section":"Canonical Telemetry","url":"sections/telemetry.html#why-canonical","text":"Why canonical telemetry DeltaCore sits above multiple providers. All inbound telemetry must be normalized into a canonical schema before analytics or alerting.","tags":["telemetry","ingestion","normalization","j1939"],"status":"planned"},{"id":"telemetry-fields","title":"Key fields","section":"Canonical Telemetry","url":"sections/telemetry.html#fields","text":"Key fields timestamp_utc, tenant_id, site_id, equipment_id source_provider, source_asset_id metric_type, metric_unit, numeric_value status_or_quality_flag, data_quality_score latitude, longitude, engine_hours, odometer fuel_level, fuel_rate, ignition_state","tags":["telemetry","ingestion","normalization","j1939"],"status":"planned"},{"id":"telemetry-rules","title":"Telemetry rules","section":"Canonical Telemetry","url":"sections/telemetry.html#rules","text":"Telemetry rules Define accepted units and standard conversion rules Support event-based and time-series telemetry Track missing data, delayed records and duplicates Maintain raw-provider references for auditability and replay Idempotent ingestion using provider event IDs or hashes","tags":["telemetry","ingestion","normalization","j1939"],"status":"planned"},{"id":"vision","title":"Executive Vision","section":"Executive Vision","url":"sections/vision.html","text":"Executive Vision DeltaCore augments existing telemetry providers rather than replacing them. Dingo augment vision petroman ava telematics fuel Vision statement DeltaCore is an industrial intelligence platform that augments existing mining, fleet and telemetry systems by transforming operational data into actionable insights. DeltaCore enhances providers such as PetroMan, AVA and Dingo rather than replacing them. Product goals Reduce operating costs through fuel optimization and loss prevention Detect fuel theft, anomalies and abnormal consumption Increase equipment uptime via predictive maintenance insights Improve operator performance through scoring and benchmarking Provide enterprise dashboards, reporting and real-time alerting Integrate with existing telemetry providers Value proposition PetroMan and similar systems collect data. DeltaCore provides intelligence — forecasting, anomaly detection, optimization and fleet-wide insights delivered as an enhancement layer through APIs and dashboards.","tags":["vision","petroman","ava","telematics","fuel"],"status":"live"},{"id":"vision-vision-statement","title":"Vision statement","section":"Executive Vision","url":"sections/vision.html#vision-statement","text":"Vision statement DeltaCore is an industrial intelligence platform that augments existing mining, fleet and telemetry systems by transforming operational data into actionable insights. DeltaCore enhances providers such as PetroMan, AVA and Dingo rather than replacing them.","tags":["vision","petroman","ava","telematics","fuel"],"status":"live"},{"id":"vision-product-goals","title":"Product goals","section":"Executive Vision","url":"sections/vision.html#product-goals","text":"Product goals Reduce operating costs through fuel optimization and loss prevention Detect fuel theft, anomalies and abnormal consumption Increase equipment uptime via predictive maintenance insights Improve operator performance through scoring and benchmarking Provide enterprise dashboards, reporting and real-time alerting Integrate with existing telemetry providers","tags":["vision","petroman","ava","telematics","fuel"],"status":"live"},{"id":"vision-value-proposition","title":"Value proposition","section":"Executive Vision","url":"sections/vision.html#value-proposition","text":"Value proposition PetroMan and similar systems collect data. DeltaCore provides intelligence — forecasting, anomaly detection, optimization and fleet-wide insights delivered as an enhancement layer through APIs and dashboards.","tags":["vision","petroman","ava","telematics","fuel"],"status":"live"}];